  beginSession(catalyst: string, stateOfMind: string): SessionRecord {
    const sessionId = `session_${Date.now()}`;
    const claimedAt = process.env.SESSION_CLAIMED_AT || new Date().toISOString();

    this.currentSession = {
      sessionId,
      timestamp: new Date().toISOString(),
      identity: {
